}: {
  pane: Pane;
  size: number;
  focused: boolean;
  canClose: boolean;
  projects: Project[];
  threads: Thread[];
  renderRoute: (r: Route) => React.ReactNode;
  onActivateTab: (key: string) => void;
  onCloseTab: (key: string) => void;
  onClosePane: () => void;
  onFocus: () => void;
  onTabDragStart: () => void;
  onTabDragEnd: () => void;
  onTabDrop: (fromPaneId: PaneId, key: string) => void;
}) {
  const onDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    if (e.dataTransfer.types.includes(TAB_DRAG_TYPE)) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
    }
  };
  const onDrop = (e: React.DragEvent<HTMLDivElement>) => {
    const data = e.dataTransfer.getData(TAB_DRAG_TYPE);
    if (!data) return;
    e.preventDefault();
    try {
      const { paneId, key } = JSON.parse(data);
      onTabDrop(paneId, key);
    } catch {}
  };
  return (
    <div
      className={`pane ${focused ? "pane-focused" : ""}`}
      style={{ flex: size }}
      onMouseDownCapture={onFocus}
      onDragOver={onDragOver}
      onDrop={onDrop}
    >
      <PaneTabsRow
        paneId={pane.id}
        tabs={pane.tabs}
        activeKey={pane.activeKey}
        projects={projects}
        threads={threads}
        canClosePane={canClose}
        onActivate={onActivateTab}
        onClose={onCloseTab}
        onClosePane={onClosePane}
        onTabDragStart={onTabDragStart}
        onTabDragEnd={onTabDragEnd}
      />
      <main className="pane-body">
        {pane.tabs.map((r) => {
          const k = routeKey(r);
          return (
            <div key={k} className="route-pane" hidden={k !== pane.activeKey}>
              {renderRoute(r)}
            </div>
          );
        })}
      </main>
    </div>
  );
}

function PaneTabsRow({
  paneId,
  tabs,
  activeKey,
  projects,
  threads,
  canClosePane,
  onActivate,
  onClose,
  onClosePane,
  onTabDragStart,
  onTabDragEnd,
}: {
  paneId: PaneId;
  tabs: Route[];
  activeKey: string;
  projects: Project[];
  threads: Thread[];
  canClosePane: boolean;
  onActivate: (key: string) => void;
  onClose: (key: string) => void;
  onClosePane: () => void;
  onTabDragStart: () => void;
  onTabDragEnd: () => void;
}) {
  return (
    <nav className="tabs-row">
      {tabs.map((r) => {
        const k = routeKey(r);
        const active = k === activeKey;
        const label = tabLabel(r, projects, threads);
        return (
          <div
            key={k}
            className={`tab ${active ? "active" : ""}`}
            draggable
            onDragStart={(e) => {
              e.dataTransfer.setData(
                TAB_DRAG_TYPE,
                JSON.stringify({ paneId, key: k }),
              );
              e.dataTransfer.effectAllowed = "move";
              onTabDragStart();
            }}
            onDragEnd={onTabDragEnd}
            onClick={() => onActivate(k)}
            onMouseDown={(e) => {
              if (e.button === 1) {
                e.preventDefault();
                onClose(k);
              }
            }}
            title={label}
          >
            <span className="tab-icon">{tabIcon(r)}</span>
            <span className="tab-label">{label}</span>
            <button
              className="tab-close"
              onClick={(e) => {
                e.stopPropagation();
                onClose(k);
              }}
              title="Закрыть"
              aria-label="Закрыть таб"
            >
              ×
            </button>
          </div>
        );
      })}
      {canClosePane && (
        <button
          className="pane-close-btn"
          onClick={onClosePane}
          title="Закрыть панель"
          aria-label="Закрыть панель"
        >
          ⨯
        </button>
      )}
    </nav>
  );
}

function NewPaneDropZone({
  active,
  onDrop,
}: {
  active: boolean;
  onDrop: (fromPaneId: PaneId, key: string) => void;
}) {
  const [over, setOver] = useState(false);
  return (
    <div
      className={`pane-newzone ${active ? "armed" : ""} ${over ? "over" : ""}`}
      onDragOver={(e) => {
        if (e.dataTransfer.types.includes(TAB_DRAG_TYPE)) {
          e.preventDefault();
          e.dataTransfer.dropEffect = "move";
          if (!over) setOver(true);
        }
      }}
      onDragLeave={() => setOver(false)}
      onDrop={(e) => {
        const data = e.dataTransfer.getData(TAB_DRAG_TYPE);
        setOver(false);
        if (!data) return;
        e.preventDefault();
        try {
          const { paneId, key } = JSON.parse(data);
          onDrop(paneId, key);
        } catch {}
      }}
    />
  );
}

function AppsScreen({
  onOpenApp,
  onOpenTopic,
}: {
  onOpenApp: (id: string) => void;
  onOpenTopic: (id: string) => void;
}) {
  const [items, setItems] = useState<AppManifest[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [creating, setCreating] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [description, setDescription] = useState("");

  async function refresh() {
    try {
      const list = await invoke<AppManifest[]>("list_apps");
      setItems(list);
    } catch (e) {
      setError(String(e));
    }
  }

  useEffect(() => {
    let alive = true;
    let timer: ReturnType<typeof setInterval> | null = null;
    const tick = () => {
      invoke<AppManifest[]>("list_apps")
        .then((list) => {
          if (!alive) return;
          setItems(list);
          // poll until everything is ready
          const stillCreating = list.some((a) => a.ready === false);
          if (!stillCreating && timer) {
            clearInterval(timer);
            timer = null;
          }
        })
        .catch((e) => alive && setError(String(e)));
    };
    tick();
    timer = setInterval(tick, 3000);
    return () => {
      alive = false;
      if (timer) clearInterval(timer);
    };
  }, []);

  async function submitCreate() {
    const text = description.trim();
    if (!text || creating) return;
    setCreating(true);
    setError(null);
    try {
      const res = await invoke<{ app_id: string; thread_id: string }>(
        "create_app",
        { description: text },
      );
      setShowModal(false);
      setDescription("");
      // refresh list a bit later (codex still working)
      setTimeout(() => void refresh(), 1500);
      // navigate to creation thread so user sees codex working
      onOpenTopic(res.thread_id);
    } catch (e) {
      console.error("[reflex] create_app failed", e);
      setError(String(e));
    } finally {
      setCreating(false);
    }
  }

  return (
    <div className="apps-root">
      <header className="apps-header">
        <div className="apps-header-row">
          <h1 className="section-title">Apps</h1>
          <button
            className="apps-create-btn"
            onClick={() => setShowModal(true)}
          >
            + New App
          </button>
        </div>
        <p className="apps-hint">
          Утилиты, общающиеся с агентом через мост Reflex. Опиши что хочешь —
          codex напишет.
        </p>
      </header>
      {error && <div className="apps-error">{error}</div>}
      {items.length === 0 ? (
        <div className="chat-empty">
          <p>Apps пока нет.</p>
        </div>
      ) : (
        <div className="apps-grid">
          {items.map((a) => {
            const isReady = a.ready !== false;
            return (
              <button
                key={a.id}
                className={`apps-card ${isReady ? "" : "apps-card-creating"}`}
                disabled={!isReady}
                onClick={() => isReady && onOpenApp(a.id)}
                title={isReady ? "Открыть" : "Codex ещё пишет файлы…"}
              >
                <div className="apps-card-icon">{a.icon ?? "🧩"}</div>
                <div className="apps-card-name">
                  {a.name}
                  {!isReady && (
                    <span className="apps-card-badge">creating…</span>
                  )}
                </div>
                {a.description && (
                  <div className="apps-card-desc">{a.description}</div>
                )}
                {a.permissions.length > 0 && (
                  <div className="apps-card-perms">
                    {a.permissions.map((p) => (
                      <span key={p} className="apps-perm">
                        {p}
                      </span>
                    ))}
                  </div>
                )}
              </button>
            );
          })}
        </div>
      )}
      {showModal && (
        <div
          className="modal-backdrop"
          onClick={() => !creating && setShowModal(false)}
        >
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <h2 className="modal-title">Новый Reflex app</h2>
            <p className="modal-hint">
              Опиши коротко что должен делать app. Codex напишет index.html и
              манифест в фоне.
            </p>
            <textarea
              className="modal-input"
              placeholder="Например: счётчик с кнопкой сохранения в storage; виджет погоды через agent.ask; …"
              value={description}
              onChange={(e) => setDescription(e.currentTarget.value)}
              autoFocus
              rows={5}
            />
            <div className="modal-actions">
              <button
                className="modal-btn"
                disabled={creating}
                onClick={() => setShowModal(false)}
              >
                Отмена
              </button>
              <button
                className="modal-btn modal-btn-primary"
                disabled={creating || !description.trim()}
                onClick={() => void submitCreate()}
              >
                {creating ? "Создаю…" : "Создать"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

