    return () => {
      alive = false;
      clearInterval(timer);
    };
  }, [appId, manifest?.runtime, serverState]);

  async function restartServer() {
    if (busy) return;
    setBusy("restart");
    setServerError(null);
    try {
      const port = await invoke<number>("app_server_restart", { appId });
      setServerPort(port);
      setServerState("running");
      setReloadKey((k) => k + 1);
    } catch (e) {
      setServerError(String(e));
      setServerState("failed");
    } finally {
