    let dir = apps::app_dir(app, app_id).map_err(|e| e.to_string())?;
    if let Some(p) = project::find_project_for(&dir) {
        return Ok(p);
    }
    let manifest = apps::read_manifest(app, app_id).ok();
    let proj_name = manifest
        .as_ref()
